// frontend/src/pages/HomePage.jsx (updated to use PostCard)
import { useState, useEffect } from 'react';
import PostCard from '../components/PostCard';
import API from '../api/axios';
import styles from '../styles/HomePage.module.css';

const HomePage = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .catch(err => console.error('Error fetching posts:', err))
      .finally(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className={styles.loading}>
        <div className={styles.loadingSpinner}></div>
        <p>Loading posts from the Land of Dawn...</p>
      </div>
    );
  }

  return (
    <div className={styles.homePage}>
      <div className={styles.hero}>
        <h1>Welcome to MLFolio ⚔️</h1>
        <p>Discover epic gaming achievements, strategies, and stories from the battlefield!</p>
      </div>

      <div className={styles.container}>
        <h2 className={styles.sectionTitle}>Latest Battle Stories</h2>
        
        {posts.length === 0 ? (
          <div className={styles.noPosts}>
            <p>No posts yet. Be the first to share your epic victory! 🎮</p>
          </div>
        ) : (
          <div className={styles.postsGrid}>
            {posts.map(post => (
              <PostCard key={post._id} post={post} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default HomePage;
